    <button hx-get="/edit-content-row/{{ item.id }}" hx-target="#row-{{ item.id }}" hx-swap="outerHTML" class="w-full bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-200 px-3 py-1.5 rounded text-xs font-bold shadow-sm transition-colors opacity-0 group-hover:opacity-100">Edit</button>
{% elif item.status == 'failed' or item.status == 'rewriting' %}
     <button hx-post="/reset-failure/{{ item.id }}" hx-target="#row-{{ item.id }}" hx-swap="outerHTML" class="w-full bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-200 px-3 py-1.5 rounded text-xs font-bold shadow-sm transition-colors">Reset</button>
{% endif %}

{% if item.status == 'idea' or item.status == 'failed' or item.status == 'rewriting' %}
    <button hx-delete="/delete-item/{{ item.id }}" hx-confirm="Delete '{{ item.topic }}' permanently?" hx-target="#row-{{ item.id }}" hx-swap="outerHTML" class="w-full text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 px-3 py-1.5 rounded text-xs font-bold transition-colors opacity-0 group-hover:opacity-100">Delete</button>
{% endif %}

